-- ============================================================================
-- Quiz Seed: 1 Thessalonians (Chapters 1–5)
-- 3 difficulties × 5 chapters = 80 total questions
--   kids:   3 per chapter  = 15
--   teens:  5 per chapter  = 25
--   adults: 8 per chapter  = 40
-- ============================================================================

-- ═══ 1 Thessalonians Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Thessalonians', 1, 'kids', 1, 'Who wrote this letter to the Thessalonians?', 'Paul', 'Peter', 'James', 'John', 'a', '1 Thessalonians 1:1 — "Paul, and Silvanus, and Timotheus, unto the church of the Thessalonians."'),
('1 Thessalonians', 1, 'kids', 2, 'What three things did Paul thank God the Thessalonians had?', 'Faith, love, and hope', 'Gold, silver, and jewels', 'Swords, shields, and armor', 'Horses, chariots, and soldiers', 'a', '1 Thessalonians 1:3 — "Your work of faith, and labour of love, and patience of hope."'),
('1 Thessalonians', 1, 'kids', 3, 'The Thessalonians turned from idols to serve whom?', 'The living and true God', 'The Roman emperor', 'The Greek gods', 'Their own desires', 'a', '1 Thessalonians 1:9 — "Ye turned to God from idols to serve the living and true God."'),
-- Teens
('1 Thessalonians', 1, 'teens', 1, 'How did the gospel come to the Thessalonians according to verse 5?', 'Not in word only, but also in power, and in the Holy Ghost', 'Only through written letters', 'Only through human reasoning', 'Only through signs and wonders', 'a', '1 Thessalonians 1:5 — "Our gospel came not unto you in word only, but also in power, and in the Holy Ghost, and in much assurance."'),
('1 Thessalonians', 1, 'teens', 2, 'What did the Thessalonians become to believers in Macedonia and Achaia?', 'Examples (ensamples) to all that believe', 'Financial supporters', 'Political leaders', 'Military commanders', 'a', '1 Thessalonians 1:7 — "So that ye were ensamples to all that believe in Macedonia and Achaia."'),
('1 Thessalonians', 1, 'teens', 3, 'Despite receiving the word in much affliction, what did the Thessalonians have?', 'Joy of the Holy Ghost', 'Anger at their persecutors', 'Desire for revenge', 'Plans to flee the city', 'a', '1 Thessalonians 1:6 — "Having received the word in much affliction, with joy of the Holy Ghost."'),
('1 Thessalonians', 1, 'teens', 4, 'What sounded out from the Thessalonians in every place?', 'The word of the Lord', 'Complaints about Rome', 'Requests for money', 'Political speeches', 'a', '1 Thessalonians 1:8 — "For from you sounded out the word of the Lord not only in Macedonia and Achaia, but also in every place."'),
('1 Thessalonians', 1, 'teens', 5, 'Who are the Thessalonians waiting for from heaven?', 'God''s Son Jesus, who delivers us from the wrath to come', 'An angel with a sword', 'A new king for Israel', 'The prophet Elijah', 'a', '1 Thessalonians 1:10 — "To wait for his Son from heaven... even Jesus, which delivered us from the wrath to come."'),
-- Adults
('1 Thessalonians', 1, 'adults', 1, 'Who are the co-senders of this epistle with Paul?', 'Silvanus and Timotheus', 'Barnabas and Luke', 'Titus and Apollos', 'Peter and James', 'a', '1 Thessalonians 1:1 — "Paul, and Silvanus, and Timotheus, unto the church of the Thessalonians."'),
('1 Thessalonians', 1, 'adults', 2, 'What does Paul say he knows about the Thessalonians'' election in verse 4?', 'Their election of God', 'Their political elections', 'Their choice of leaders', 'Their selection of teachers', 'a', '1 Thessalonians 1:4 — "Knowing, brethren beloved, your election of God."'),
('1 Thessalonians', 1, 'adults', 3, 'Who did the Thessalonians become followers of according to verse 6?', 'Paul and the Lord', 'The Roman governors', 'The Jewish Sanhedrin', 'The Greek philosophers', 'a', '1 Thessalonians 1:6 — "And ye became followers of us, and of the Lord."'),
('1 Thessalonians', 1, 'adults', 4, 'What does Paul say the Thessalonians'' faith had done geographically?', 'Their faith to God-ward had spread abroad in every place', 'Their faith was confined to Thessalonica', 'Their faith only reached Macedonia', 'Their faith was known only to Paul', 'a', '1 Thessalonians 1:8 — "Your faith to God-ward is spread abroad; so that we need not to speak any thing."'),
('1 Thessalonians', 1, 'adults', 5, 'What two actions describe the Thessalonians'' conversion in verse 9?', 'They turned to God from idols to serve the living and true God', 'They left their homes and moved to Jerusalem', 'They stopped eating and began fasting', 'They destroyed all Greek temples', 'a', '1 Thessalonians 1:9 — "Ye turned to God from idols to serve the living and true God."'),
('1 Thessalonians', 1, 'adults', 6, 'What eschatological hope is mentioned in verse 10?', 'Waiting for God''s Son from heaven whom he raised from the dead', 'Waiting for the temple to be rebuilt', 'Waiting for Rome to fall', 'Waiting for a new prophet', 'a', '1 Thessalonians 1:10 — "And to wait for his Son from heaven, whom he raised from the dead."'),
('1 Thessalonians', 1, 'adults', 7, 'What does Jesus deliver believers from according to verse 10?', 'The wrath to come', 'Physical death', 'Roman persecution', 'Earthly poverty', 'a', '1 Thessalonians 1:10 — "Even Jesus, which delivered us from the wrath to come."'),
('1 Thessalonians', 1, 'adults', 8, 'What does Paul''s mention of "much assurance" in verse 5 suggest about his ministry?', 'The gospel was confirmed by the conviction of the Holy Spirit, not just human persuasion', 'Paul was extremely confident in his own abilities', 'The Thessalonians guaranteed Paul''s safety', 'Paul had official documents proving his authority', 'a', '1 Thessalonians 1:5 — "In power, and in the Holy Ghost, and in much assurance." This indicates the Spirit''s confirming work in both preacher and hearers.');

-- ═══ 1 Thessalonians Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Thessalonians', 2, 'kids', 1, 'How did Paul say he treated the Thessalonians?', 'Gently, like a nursing mother caring for children', 'Harshly, like a strict teacher', 'Carelessly, ignoring their needs', 'Angrily, yelling at them', 'a', '1 Thessalonians 2:7 — "We were gentle among you, even as a nurse cherisheth her children."'),
('1 Thessalonians', 2, 'kids', 2, 'Did Paul work hard or was he lazy when he visited?', 'He worked hard night and day', 'He was lazy and did nothing', 'He only worked one day a week', 'He made others work for him', 'a', '1 Thessalonians 2:9 — "Labouring night and day, because we would not be chargeable unto any of you."'),
('1 Thessalonians', 2, 'kids', 3, 'What did Paul call the Thessalonians in verse 19?', 'His hope, joy, and crown', 'His students', 'His servants', 'His employees', 'a', '1 Thessalonians 2:19 — "For what is our hope, or joy, or crown of rejoicing? Are not even ye?"'),
-- Teens
('1 Thessalonians', 2, 'teens', 1, 'Where had Paul been shamefully treated before coming to Thessalonica?', 'Philippi', 'Athens', 'Corinth', 'Ephesus', 'a', '1 Thessalonians 2:2 — "Even after that we had suffered before, and were shamefully entreated, as ye know, at Philippi."'),
('1 Thessalonians', 2, 'teens', 2, 'What did Paul say he never used as a cloke (cover) for his motives?', 'Flattering words or covetousness', 'The name of God', 'Miraculous signs', 'His apostolic authority', 'a', '1 Thessalonians 2:5 — "For neither at any time used we flattering words, as ye know, nor a cloke of covetousness; God is witness."'),
('1 Thessalonians', 2, 'teens', 3, 'How does Paul describe a father''s role with his children as a model for ministry?', 'Exhorting, comforting, and charging them to walk worthy of God', 'Punishing them severely for any mistake', 'Leaving them to figure things out alone', 'Giving them whatever they wanted', 'a', '1 Thessalonians 2:11-12 — "As a father doth his children, Exhorting and comforting and charging... that ye would walk worthy of God."'),
('1 Thessalonians', 2, 'teens', 4, 'What did the Thessalonians receive Paul''s message as?', 'The word of God, which effectually worketh in believers', 'Just another human opinion', 'An interesting philosophy', 'A political manifesto', 'a', '1 Thessalonians 2:13 — "Ye received it not as the word of men, but as it is in truth, the word of God, which effectually worketh also in you that believe."'),
('1 Thessalonians', 2, 'teens', 5, 'Who does Paul say hindered him from coming to the Thessalonians?', 'Satan', 'The Roman governor', 'The Jewish leaders', 'Timothy', 'a', '1 Thessalonians 2:18 — "We would have come unto you, even I Paul, once and again; but Satan hindered us."'),
-- Adults
('1 Thessalonians', 2, 'adults', 1, 'What does Paul say about seeking glory from men in verse 6?', 'They did not seek glory of men, neither of the Thessalonians nor of others', 'They sought glory from the Roman authorities', 'They wanted recognition from Jerusalem', 'They desired fame throughout Greece', 'a', '1 Thessalonians 2:6 — "Nor of men sought we glory, neither of you, nor yet of others."'),
('1 Thessalonians', 2, 'adults', 2, 'What apostolic right did Paul say he could have used but chose not to?', 'Being burdensome (claiming financial support) as apostles of Christ', 'Demanding the best seats in synagogues', 'Requiring bodyguards from the church', 'Insisting on special food and lodging', 'a', '1 Thessalonians 2:6-7 — "When we might have been burdensome, as the apostles of Christ. But we were gentle among you."'),
('1 Thessalonians', 2, 'adults', 3, 'What does Paul say the Jews did that filled up their sins in verse 16?', 'Forbidding the apostles to speak to the Gentiles that they might be saved', 'Rebuilding the temple without permission', 'Refusing to pay Roman taxes', 'Declaring war against Rome', 'a', '1 Thessalonians 2:16 — "Forbidding us to speak to the Gentiles that they might be saved, to fill up their sins alway."'),
('1 Thessalonians', 2, 'adults', 4, 'What does Paul say came upon the opposing Jews "to the uttermost"?', 'Wrath', 'Blessing', 'Wisdom', 'Prosperity', 'a', '1 Thessalonians 2:16 — "For the wrath is come upon them to the uttermost."'),
('1 Thessalonians', 2, 'adults', 5, 'What does Paul mean by being "taken from you" in verse 17?', 'Being separated in presence but not in heart (orphaned from them physically)', 'Dying and going to heaven', 'Being captured by enemies', 'Voluntarily leaving the faith', 'a', '1 Thessalonians 2:17 — "Being taken from you for a short time in presence, not in heart, endeavoured the more abundantly to see your face with great desire."'),
('1 Thessalonians', 2, 'adults', 6, 'Before whom does Paul say the Thessalonians are his crown of rejoicing?', 'Before our Lord Jesus Christ at his coming', 'Before the Roman emperor', 'Before the other apostles', 'Before the Jewish leaders', 'a', '1 Thessalonians 2:19 — "Are not even ye in the presence of our Lord Jesus Christ at his coming?"'),
('1 Thessalonians', 2, 'adults', 7, 'What churches does Paul say the Thessalonians became followers of in verse 14?', 'The churches of God in Judaea which are in Christ Jesus', 'The churches in Rome', 'The churches in Ephesus', 'The churches in Corinth', 'a', '1 Thessalonians 2:14 — "For ye, brethren, became followers of the churches of God which in Judaea are in Christ Jesus."'),
('1 Thessalonians', 2, 'adults', 8, 'What bold claim does Paul make about his preaching motive in verse 4?', 'Not as pleasing men but God, which trieth our hearts', 'To gain followers for his own ministry', 'To become famous throughout the Roman Empire', 'To compete with other apostles', 'a', '1 Thessalonians 2:4 — "But as we were allowed of God to be put in trust with the gospel, even so we speak; not as pleasing men, but God, which trieth our hearts."');

-- ═══ 1 Thessalonians Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Thessalonians', 3, 'kids', 1, 'Who did Paul send to check on the Thessalonians?', 'Timothy', 'Peter', 'Barnabas', 'Luke', 'a', '1 Thessalonians 3:2 — "And sent Timotheus, our brother, and minister of God."'),
('1 Thessalonians', 3, 'kids', 2, 'What good news did Timothy bring back about the Thessalonians?', 'Good news of their faith and love', 'Bad news about fighting', 'News about their wealth', 'News about a new building', 'a', '1 Thessalonians 3:6 — "When Timotheus came from you unto us, and brought us good tidings of your faith and charity."'),
('1 Thessalonians', 3, 'kids', 3, 'How did Paul feel when he heard about their faith?', 'Comforted and joyful', 'Angry and upset', 'Bored and tired', 'Scared and worried', 'a', '1 Thessalonians 3:7 — "We were comforted over you in all our affliction and distress by your faith."'),
-- Teens
('1 Thessalonians', 3, 'teens', 1, 'Why did Paul send Timothy to the Thessalonians?', 'To establish and comfort them concerning their faith', 'To collect money for the church in Jerusalem', 'To start a new church nearby', 'To recruit soldiers for Paul', 'a', '1 Thessalonians 3:2 — "To establish you, and to comfort you concerning your faith."'),
('1 Thessalonians', 3, 'teens', 2, 'What did Paul fear about the Thessalonians?', 'That the tempter had tempted them and his labour was in vain', 'That they had become wealthy and proud', 'That they had moved to another city', 'That they had forgotten his name', 'a', '1 Thessalonians 3:5 — "Lest by some means the tempter have tempted you, and our labour be in vain."'),
('1 Thessalonians', 3, 'teens', 3, 'What did Paul say believers are appointed to in verse 3?', 'Afflictions', 'Prosperity', 'Political power', 'Earthly comfort', 'a', '1 Thessalonians 3:3 — "That no man should be moved by these afflictions: for yourselves know that we are appointed thereunto."'),
('1 Thessalonians', 3, 'teens', 4, 'What does Paul say about their faith that he wants to perfect?', 'That which is lacking in their faith', 'Their understanding of Roman law', 'Their knowledge of Greek philosophy', 'Their ability to work miracles', 'a', '1 Thessalonians 3:10 — "Night and day praying exceedingly that we might see your face, and might perfect that which is lacking in your faith."'),
('1 Thessalonians', 3, 'teens', 5, 'What does Paul pray would increase and abound among them?', 'Love one toward another, and toward all men', 'Knowledge and wisdom', 'Wealth and possessions', 'Political influence', 'a', '1 Thessalonians 3:12 — "The Lord make you to increase and abound in love one toward another, and toward all men."'),
-- Adults
('1 Thessalonians', 3, 'adults', 1, 'Where was Paul left alone when he sent Timothy to Thessalonica?', 'Athens', 'Corinth', 'Ephesus', 'Rome', 'a', '1 Thessalonians 3:1 — "When we could no longer forbear, we thought it good to be left at Athens alone."'),
('1 Thessalonians', 3, 'adults', 2, 'What three titles does Paul give Timothy in verse 2?', 'Brother, minister of God, and fellowlabourer in the gospel of Christ', 'Apostle, prophet, and evangelist', 'Bishop, elder, and deacon', 'Scribe, teacher, and priest', 'a', '1 Thessalonians 3:2 — "Timotheus, our brother, and minister of God, and our fellowlabourer in the gospel of Christ."'),
('1 Thessalonians', 3, 'adults', 3, 'What does Paul say he told the Thessalonians beforehand?', 'That they would suffer tribulation, which came to pass', 'That they would become wealthy', 'That Rome would fall', 'That Christ would return immediately', 'a', '1 Thessalonians 3:4 — "When we were with you, we told you before that we should suffer tribulation; even as it came to pass."'),
('1 Thessalonians', 3, 'adults', 4, 'What does Paul say gives him life in verse 8?', 'If ye stand fast in the Lord', 'If they send him financial support', 'If they build a new church', 'If they convert the Roman governor', 'a', '1 Thessalonians 3:8 — "For now we live, if ye stand fast in the Lord."'),
('1 Thessalonians', 3, 'adults', 5, 'What is the goal of Paul''s prayer in verse 13?', 'To establish their hearts unblameable in holiness before God at the coming of the Lord Jesus', 'To make them wealthy and prosperous', 'To give them political authority', 'To make them famous throughout the world', 'a', '1 Thessalonians 3:13 — "To the end he may stablish your hearts unblameable in holiness before God, even our Father, at the coming of our Lord Jesus Christ with all his saints."'),
('1 Thessalonians', 3, 'adults', 6, 'What does the reference to "the coming of our Lord Jesus Christ with all his saints" in verse 13 affirm?', 'The bodily return of Christ accompanied by all believers', 'A spiritual metaphor for inner peace', 'The destruction of Rome', 'The restoration of Israel''s kingdom', 'a', '1 Thessalonians 3:13 — "At the coming of our Lord Jesus Christ with all his saints." This affirms the literal Second Coming.'),
('1 Thessalonians', 3, 'adults', 7, 'What does Paul''s phrase "we could no longer forbear" (v.1,5) reveal about his pastoral heart?', 'His deep anxiety and love for the believers drove him to send Timothy despite his own need', 'He was merely curious about their progress', 'He was following an organizational protocol', 'He was required by the church to check on them', 'a', '1 Thessalonians 3:1,5 — "When we could no longer forbear" shows Paul''s intense concern for their spiritual welfare.'),
('1 Thessalonians', 3, 'adults', 8, 'What does Paul''s thankfulness in verse 9 suggest about the relationship between a pastor and his flock?', 'A pastor''s deepest joy comes from the spiritual wellbeing of those he serves', 'A pastor should seek financial reward', 'A pastor should remain emotionally detached', 'A pastor''s joy depends on church size', 'a', '1 Thessalonians 3:9 — "For what thanks can we render to God again for you, for all the joy wherewith we joy for your sakes before our God."');

-- ═══ 1 Thessalonians Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Thessalonians', 4, 'kids', 1, 'What does God want us to do according to Paul?', 'Live holy lives', 'Be the richest person', 'Fight with everyone', 'Think only about ourselves', 'a', '1 Thessalonians 4:3 — "For this is the will of God, even your sanctification."'),
('1 Thessalonians', 4, 'kids', 2, 'What will happen when Jesus comes back?', 'The dead in Christ shall rise first', 'Everyone will stay sleeping', 'Nothing will happen', 'Only angels will come', 'a', '1 Thessalonians 4:16 — "And the dead in Christ shall rise first."'),
('1 Thessalonians', 4, 'kids', 3, 'Where will believers meet the Lord?', 'In the air', 'In the temple', 'At a mountain', 'In the sea', 'a', '1 Thessalonians 4:17 — "Then we which are alive and remain shall be caught up together with them in the clouds, to meet the Lord in the air."'),
-- Teens
('1 Thessalonians', 4, 'teens', 1, 'What is the will of God according to verse 3?', 'Your sanctification', 'Your wealth', 'Your political power', 'Your popularity', 'a', '1 Thessalonians 4:3 — "For this is the will of God, even your sanctification."'),
('1 Thessalonians', 4, 'teens', 2, 'What does Paul say believers should do about those who have died (fallen asleep)?', 'Not sorrow as others which have no hope', 'Forget about them completely', 'Be angry at God', 'Give up their own faith', 'a', '1 Thessalonians 4:13 — "That ye sorrow not, even as others which have no hope."'),
('1 Thessalonians', 4, 'teens', 3, 'What three sounds accompany the Lord''s descent from heaven?', 'A shout, the voice of the archangel, and the trump of God', 'Thunder, lightning, and earthquake', 'Trumpets, drums, and cymbals', 'Singing, clapping, and shouting', 'a', '1 Thessalonians 4:16 — "For the Lord himself shall descend from heaven with a shout, with the voice of the archangel, and with the trump of God."'),
('1 Thessalonians', 4, 'teens', 4, 'What should believers comfort each other with?', 'These words about the Lord''s return', 'Promises of earthly wealth', 'Stories of Greek heroes', 'Plans for revenge against enemies', 'a', '1 Thessalonians 4:18 — "Wherefore comfort one another with these words."'),
('1 Thessalonians', 4, 'teens', 5, 'How does Paul say believers should behave toward outsiders?', 'Walk honestly and have lack of nothing', 'Avoid all contact with them', 'Try to impress them with wealth', 'Argue with them about religion', 'a', '1 Thessalonians 4:12 — "That ye may walk honestly toward them that are without, and that ye may have lack of nothing."'),
-- Adults
('1 Thessalonians', 4, 'adults', 1, 'What does Paul mean by "possess his vessel in sanctification and honour" in verse 4?', 'Controlling one''s own body in holiness and honor', 'Owning a sacred artifact', 'Possessing a clean drinking vessel', 'Having a boat for missionary journeys', 'a', '1 Thessalonians 4:4 — "That every one of you should know how to possess his vessel in sanctification and honour."'),
('1 Thessalonians', 4, 'adults', 2, 'What does Paul say God has called believers to in verse 7?', 'Holiness, not uncleanness', 'Wealth and prosperity', 'Political leadership', 'Miraculous powers', 'a', '1 Thessalonians 4:7 — "For God hath not called us unto uncleanness, but unto holiness."'),
('1 Thessalonians', 4, 'adults', 3, 'What does Paul say about rejecting these instructions in verse 8?', 'He that despiseth, despiseth not man, but God who hath given us his Holy Spirit', 'It is just Paul''s personal opinion', 'It doesn''t really matter', 'It only applies to church leaders', 'a', '1 Thessalonians 4:8 — "He therefore that despiseth, despiseth not man, but God, who hath also given unto us his holy Spirit."'),
('1 Thessalonians', 4, 'adults', 4, 'What does Paul say about brotherly love being taught?', 'They are taught of God to love one another', 'They learned it from Greek philosophy', 'They were taught by Roman educators', 'They figured it out on their own', 'a', '1 Thessalonians 4:9 — "As touching brotherly love ye need not that I write unto you: for ye yourselves are taught of God to love one another."'),
('1 Thessalonians', 4, 'adults', 5, 'What three practical instructions does Paul give in verse 11?', 'Study to be quiet, do your own business, work with your own hands', 'Preach loudly, meddle in others'' affairs, avoid manual labor', 'Travel widely, seek adventure, avoid routine', 'Debate fiercely, lead politically, accumulate wealth', 'a', '1 Thessalonians 4:11 — "That ye study to be quiet, and to do your own business, and to work with your own hands, as we commanded you."'),
('1 Thessalonians', 4, 'adults', 6, 'What is the theological significance of the phrase "the dead in Christ shall rise first" (v.16)?', 'Deceased believers have priority in the resurrection order, followed by living believers being caught up', 'Only dead believers will be resurrected', 'Living believers are not included in the rapture', 'The dead in Christ are already in heaven', 'a', '1 Thessalonians 4:16 — "And the dead in Christ shall rise first." This establishes the order: resurrection of dead believers, then transformation of living believers.'),
('1 Thessalonians', 4, 'adults', 7, 'What does the phrase "caught up together" (harpazo in Greek) in verse 17 mean?', 'Snatched away suddenly and forcefully — the basis for the doctrine of the rapture', 'A gradual ascension over many days', 'A metaphor for spiritual enlightenment', 'A political movement to overthrow Rome', 'a', '1 Thessalonians 4:17 — "Then we which are alive and remain shall be caught up together with them in the clouds." The Greek harpazo means to seize or snatch away suddenly.'),
('1 Thessalonians', 4, 'adults', 8, 'What is the ultimate promise in verse 17 about believers'' relationship with the Lord?', 'So shall we ever be with the Lord — eternal, unbroken fellowship', 'We will serve the Lord for 1,000 years', 'We will be sent on missions throughout the universe', 'We will sleep until the final judgment', 'a', '1 Thessalonians 4:17 — "And so shall we ever be with the Lord." The ultimate hope is permanent, unending communion with Christ.');

-- ═══ 1 Thessalonians Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Thessalonians', 5, 'kids', 1, 'How will the day of the Lord come?', 'Like a thief in the night', 'With a big parade', 'After a long warning', 'When everyone is ready', 'a', '1 Thessalonians 5:2 — "The day of the Lord so cometh as a thief in the night."'),
('1 Thessalonians', 5, 'kids', 2, 'What does Paul say to do always?', 'Rejoice evermore (be joyful always)', 'Complain about everything', 'Sleep all day', 'Worry about tomorrow', 'a', '1 Thessalonians 5:16 — "Rejoice evermore."'),
('1 Thessalonians', 5, 'kids', 3, 'What does Paul say about praying?', 'Pray without ceasing', 'Only pray on Sundays', 'Never pray out loud', 'Pray only when you are sad', 'a', '1 Thessalonians 5:17 — "Pray without ceasing."'),
-- Teens
('1 Thessalonians', 5, 'teens', 1, 'What will people be saying when sudden destruction comes?', 'Peace and safety', 'War and destruction', 'Judgment and wrath', 'Famine and plague', 'a', '1 Thessalonians 5:3 — "For when they shall say, Peace and safety; then sudden destruction cometh upon them."'),
('1 Thessalonians', 5, 'teens', 2, 'What are believers called children of in verse 5?', 'Children of light and children of the day', 'Children of the world', 'Children of Abraham', 'Children of the temple', 'a', '1 Thessalonians 5:5 — "Ye are all the children of light, and the children of the day."'),
('1 Thessalonians', 5, 'teens', 3, 'What spiritual armor does Paul mention in verse 8?', 'The breastplate of faith and love, and the helmet of the hope of salvation', 'A sword and a shield', 'A crown and a scepter', 'Sandals and a belt', 'a', '1 Thessalonians 5:8 — "Putting on the breastplate of faith and love; and for an helmet, the hope of salvation."'),
('1 Thessalonians', 5, 'teens', 4, 'What three short commands does Paul give in verses 16-18?', 'Rejoice evermore, pray without ceasing, in every thing give thanks', 'Fight bravely, run fast, eat well', 'Study hard, work harder, sleep little', 'Speak loudly, act boldly, think wisely', 'a', '1 Thessalonians 5:16-18 — "Rejoice evermore. Pray without ceasing. In every thing give thanks."'),
('1 Thessalonians', 5, 'teens', 5, 'What does Paul say about the Spirit in verse 19?', 'Quench not the Spirit', 'Ignore the Spirit', 'Control the Spirit', 'Question the Spirit', 'a', '1 Thessalonians 5:19 — "Quench not the Spirit."'),
-- Adults
('1 Thessalonians', 5, 'adults', 1, 'What analogy does Paul use for sudden destruction in verse 3?', 'Travail upon a woman with child — they shall not escape', 'A flood sweeping away a village', 'A fire consuming a forest', 'An earthquake destroying a city', 'a', '1 Thessalonians 5:3 — "Then sudden destruction cometh upon them, as travail upon a woman with child; and they shall not escape."'),
('1 Thessalonians', 5, 'adults', 2, 'What does Paul say God has NOT appointed believers to in verse 9?', 'Wrath, but to obtain salvation by our Lord Jesus Christ', 'Suffering of any kind', 'Work or labor', 'Physical death', 'a', '1 Thessalonians 5:9 — "For God hath not appointed us to wrath, but to obtain salvation by our Lord Jesus Christ."'),
('1 Thessalonians', 5, 'adults', 3, 'Whether we wake or sleep, what does Paul say in verse 10?', 'We should live together with him', 'We should fear judgment', 'We should remain uncertain', 'We should withdraw from the world', 'a', '1 Thessalonians 5:10 — "Who died for us, that, whether we wake or sleep, we should live together with him."'),
('1 Thessalonians', 5, 'adults', 4, 'What does "in every thing give thanks" in verse 18 mean in context?', 'This is the will of God in Christ Jesus concerning you', 'It is Paul''s personal suggestion', 'It only applies in good circumstances', 'It is optional for mature believers', 'a', '1 Thessalonians 5:18 — "In every thing give thanks: for this is the will of God in Christ Jesus concerning you."'),
('1 Thessalonians', 5, 'adults', 5, 'What does Paul say to do with prophecies in verse 20?', 'Despise not prophesyings', 'Accept all prophecies without question', 'Write all prophecies in a book', 'Only listen to prophecy from apostles', 'a', '1 Thessalonians 5:20 — "Despise not prophesyings."'),
('1 Thessalonians', 5, 'adults', 6, 'What does Paul say to prove (test) in verse 21?', 'All things; hold fast that which is good', 'Only teachings from apostles', 'Nothing — just believe everything', 'Only Old Testament prophecies', 'a', '1 Thessalonians 5:21 — "Prove all things; hold fast that which is good."'),
('1 Thessalonians', 5, 'adults', 7, 'What does Paul pray to be preserved blameless in verse 23?', 'Your whole spirit and soul and body unto the coming of our Lord Jesus Christ', 'Only the spirit', 'Only the body', 'Only the mind', 'a', '1 Thessalonians 5:23 — "I pray God your whole spirit and soul and body be preserved blameless unto the coming of our Lord Jesus Christ."'),
('1 Thessalonians', 5, 'adults', 8, 'What is the theological significance of the trichotomy "spirit and soul and body" in verse 23?', 'It affirms the three-part nature of human beings: spirit (God-consciousness), soul (self-consciousness), and body (world-consciousness)', 'It suggests humans have three separate bodies', 'It is a poetic expression with no doctrinal significance', 'It refers to three stages of Christian growth', 'a', '1 Thessalonians 5:23 — "Your whole spirit and soul and body." This verse is a key text in the trichotomist view of human nature, distinguishing spirit, soul, and body as distinct aspects of the person.');
